     1	import type { BlockNoteEditor } from "@blocknote/core";
     2	import {
     3	  UniqueID,
     4	  createExtension,
     5	  getBlockInfo,
     6	  nodeToBlock,
     7	} from "@blocknote/core";
     8	import { Plugin } from "prosemirror-state";
     9	import type { EditorView } from "prosemirror-view";
    10	import { detectEdgePosition } from "./multiColumnDropCursor.js";
    11	
    12	/**
    13	 * Creates a ProseMirror plugin that handles drop events for multi-column layouts.
    14	 * When a block is dropped near the left or right edge of another block, it creates
    15	 * or modifies column layouts.
    16	 */
    17	export function createMultiColumnHandleDropPlugin(
    18	  editor: BlockNoteEditor<any, any, any>,
    19	): Plugin {
    20	  return new Plugin({
    21	    props: {
    22	      handleDrop(view: EditorView, event: DragEvent, slice, _moved) {
    23	        const edgePos = detectEdgePosition(event, view, view.state);
    24	        if (edgePos === null) {
    25	          return false; // Let ProseMirror handle the drop (e.g. outside editor bounds)
    26	        }
    27	
    28	        const blockInfo = getBlockInfo(edgePos);
    29	
    30	        // Only handle edge drops (left/right)
    31	        if (edgePos.position === "regular") {
    32	          return false; // Let ProseMirror handle regular drops
    33	        }
    34	
    35	        if (slice.content.childCount === 0) {
    36	          return false; // Let ProseMirror handle empty slice drops
    37	        }
    38	
    39	        const draggedBlock = nodeToBlock(
    40	          slice.content.child(0),
    41	          editor.pmSchema,
    42	        );
    43	
    44	        if (blockInfo.blockNoteType === "column") {
    45	          // Insert new column in existing columnList
    46	          const parentBlock = view.state.doc
    47	            .resolve(blockInfo.bnBlock.beforePos)
    48	            .node();
    49	
    50	          const columnList = nodeToBlock<any, any, any>(
    51	            parentBlock,
    52	            editor.pmSchema,
    53	          );
    54	
    55	          // Normalize column widths to average of 1
    56	          // In a `columnList`, we expect that the average width of each column
    57	          // is 1. However, there are cases in which this stops being true. For
    58	          // example, having one wider column and then removing it will cause
    59	          // the average width to go down. This isn't really an issue until the
    60	          // user tries to add a new column, which will, in this case, be wider
    61	          // than expected. Therefore, we normalize the column widths to an
    62	          // average of 1 here to avoid this issue.
    63	          let sumColumnWidthPercent = 0;
    64	          columnList.children.forEach((column) => {
    65	            sumColumnWidthPercent += column.props.width as number;
    66	          });
    67	          const avgColumnWidthPercent =
    68	            sumColumnWidthPercent / columnList.children.length;
    69	
    70	          // If the average column width is not 1, normalize it. We're dealing
    71	          // with floats so we need a small margin to account for precision
    72	          // errors.
    73	          if (avgColumnWidthPercent < 0.99 || avgColumnWidthPercent > 1.01) {
    74	            const scalingFactor = 1 / avgColumnWidthPercent;
    75	
    76	            columnList.children.forEach((column) => {
    77	              column.props.width =
    78	                (column.props.width as number) * scalingFactor;
    79	            });
    80	          }
    81	
    82	          const index = columnList.children.findIndex(
    83	            (b) => b.id === blockInfo.bnBlock.node.attrs.id,
    84	          );
    85	
    86	          const newChildren = columnList.children
    87	            // If the dragged block is in one of the columns, remove it.
    88	            .map((column) => ({
    89	              ...column,
    90	              children: column.children.filter(
    91	                (block) => block.id !== draggedBlock.id,
    92	              ),
    93	            }))
    94	            // Remove empty columns (can happen when dragged block is removed).
    95	            .filter((column) => column.children.length > 0)
    96	            // Insert the dragged block in the correct position.
    97	            .toSpliced(edgePos.position === "left" ? index : index + 1, 0, {
    98	              type: "column",
    99	              children: [draggedBlock],
   100	              props: {},
   101	              content: undefined,
   102	              id: UniqueID.options.generateID(),
   103	            });
   104	
   105	          if (editor.getBlock(draggedBlock.id)) {
   106	            editor.removeBlocks([draggedBlock]);
   107	          }
   108	
   109	          editor.updateBlock(columnList, {
   110	            children: newChildren,
   111	          });
   112	        } else {
   113	          // Create new columnList with blocks as columns
   114	          const block = nodeToBlock(blockInfo.bnBlock.node, editor.pmSchema);
   115	
   116	          // The user is dropping next to the original block being dragged - do
   117	          // nothing.
   118	          if (block.id === draggedBlock.id) {
   119	            return true;
   120	          }
   121	
   122	          const blocks =
   123	            edgePos.position === "left"
   124	              ? [draggedBlock, block]
   125	              : [block, draggedBlock];
   126	
   127	          if (editor.getBlock(draggedBlock.id)) {
   128	            editor.removeBlocks([draggedBlock]);
   129	          }
   130	
   131	          editor.replaceBlocks(
   132	            [block],
   133	            [
   134	              {
   135	                type: "columnList",
   136	                children: blocks.map((b) => {
   137	                  return {
   138	                    type: "column",
   139	                    children: [b],
   140	                  };
   141	                }),
   142	              },
   143	            ],
   144	          );
   145	        }
   146	
   147	        return true; // Prevent default ProseMirror drop behavior
   148	      },
   149	    },
   150	  });
   151	}
   152	
   153	/**
   154	 * BlockNote extension that adds the multi-column drop handler plugin.
   155	 * This should be added to the editor's extensions to enable column creation via drag-and-drop.
   156	 */
   157	export const MultiColumnDropHandlerExtension = createExtension(
   158	  ({ editor }) => ({
   159	    key: "multiColumnDropHandler",
   160	    prosemirrorPlugins: [createMultiColumnHandleDropPlugin(editor)],
   161	  }),
   162	);
