     1	import { type DropCursorHooks, getNearestBlockPos } from "@blocknote/core";
     2	import type { EditorState } from "prosemirror-state";
     3	import type { EditorView } from "prosemirror-view";
     4	
     5	const PERCENTAGE_OF_BLOCK_WIDTH_CONSIDERED_SIDE_DROP = 0.1;
     6	
     7	export interface EdgeDropPosition {
     8	  position: "left" | "right" | "regular";
     9	  posBeforeNode: number;
    10	  node: any;
    11	}
    12	
    13	/**
    14	 * Detects if the drop event is near the left or right edge of a block.
    15	 * Shared utility used by both the drop cursor visualization and the drop handler.
    16	 * Returns null when the event position cannot be resolved (e.g. drop outside editor bounds).
    17	 */
    18	export function detectEdgePosition(
    19	  event: DragEvent,
    20	  view: EditorView,
    21	  state: EditorState,
    22	): EdgeDropPosition | null {
    23	  const eventPos = view.posAtCoords({
    24	    left: event.clientX,
    25	    top: event.clientY,
    26	  });
    27	
    28	  if (!eventPos) {
    29	    return null;
    30	  }
    31	
    32	  const blockPos = getNearestBlockPos(state.doc, eventPos.pos);
    33	
    34	  // If we're at a block that's in a column, we want to compare the mouse position to the column, not the block inside it
    35	  // Why? Because we want to insert a new column in the columnList, instead of a new columnList inside of the column
    36	  let resolved = state.doc.resolve(blockPos.posBeforeNode);
    37	  if (resolved.parent.type.name === "column") {
    38	    resolved = state.doc.resolve(resolved.before());
    39	  }
    40	
    41	  const posInfo = {
    42	    posBeforeNode: resolved.pos,
    43	    node: resolved.nodeAfter!,
    44	  };
    45	
    46	  const blockElement = view.nodeDOM(posInfo.posBeforeNode);
    47	  if (blockElement === null) {
    48	    return {
    49	      position: "regular",
    50	      posBeforeNode: posInfo.posBeforeNode,
    51	      node: posInfo.node,
    52	    };
    53	  }
    54	  const blockRect = (blockElement as HTMLElement).getBoundingClientRect();
    55	
    56	  let position: "regular" | "left" | "right" = "regular";
    57	
    58	  if (
    59	    event.clientX <=
    60	    blockRect.left +
    61	      blockRect.width * PERCENTAGE_OF_BLOCK_WIDTH_CONSIDERED_SIDE_DROP
    62	  ) {
    63	    position = "left";
    64	  } else if (
    65	    event.clientX >=
    66	    blockRect.right -
    67	      blockRect.width * PERCENTAGE_OF_BLOCK_WIDTH_CONSIDERED_SIDE_DROP
    68	  ) {
    69	    position = "right";
    70	  }
    71	
    72	  return {
    73	    position,
    74	    posBeforeNode: posInfo.posBeforeNode,
    75	    node: posInfo.node,
    76	  };
    77	}
    78	
    79	/**
    80	 * Creates the computeDropPosition hook for multi-column support.
    81	 * This hook detects edge drops and returns vertical cursor orientations.
    82	 */
    83	export const multiColumnDropCursor: { hooks: DropCursorHooks } = {
    84	  hooks: {
    85	    computeDropPosition: (context) => {
    86	      const edgePos = detectEdgePosition(
    87	        context.event,
    88	        context.view,
    89	        context.view.state,
    90	      );
    91	
    92	      // Fall back to default when position cannot be resolved
    93	      if (edgePos === null) {
    94	        return context.defaultPosition;
    95	      }
    96	
    97	      // If it's a regular (non-edge) drop, use the default position
    98	      if (edgePos.position === "regular") {
    99	        return context.defaultPosition;
   100	      }
   101	
   102	      // Edge drop - show vertical cursor
   103	      return {
   104	        pos: edgePos.posBeforeNode,
   105	        orientation:
   106	          edgePos.position === "left"
   107	            ? "block-vertical-left"
   108	            : "block-vertical-right",
   109	      };
   110	    },
   111	  },
   112	};
