import { describe, expect, it } from "vitest";
import { BlockNoteEditor, BlockNoteSchema } from "@blocknote/core";
import { ColumnBlock, ColumnListBlock } from "../../blocks/Columns/index.js";

const testEditorSchema = BlockNoteSchema.create().extend({
  blockSpecs: {
    column: ColumnBlock,
    columnList: ColumnListBlock,
  } as const,
});

function createEditor() {
  const editor = BlockNoteEditor.create({
    schema: testEditorSchema,
  });
  const div = document.createElement("div");
  editor.mount(div);
  return editor;
}

/**
 * Simulates a Backspace key press by directly calling the Backspace keymap handler.
 */
function pressBackspace(editor: BlockNoteEditor): boolean {
  const view = editor._tiptapEditor.view;
  const event = new KeyboardEvent("keydown", {
    key: "Backspace",
    code: "Backspace",
    bubbles: true,
    cancelable: true,
  });
  return view.someProp("handleKeyDown", (f: any) => f(view, event));
}

describe("Test Backspace after columnList", () => {
  it("should not throw when pressing backspace at start of block after columnList", () => {
    const editor = createEditor();

    editor.replaceBlocks(editor.document, [
      {
        id: "column-list-0",
        type: "columnList",
        children: [
          {
            id: "column-0",
            type: "column",
            children: [
              {
                id: "col-0-p-0",
                type: "paragraph",
                content: "Column 0 Text",
              },
            ],
          },
          {
            id: "column-1",
            type: "column",
            children: [
              {
                id: "col-1-p-0",
                type: "paragraph",
                content: "Column 1 Text",
              },
            ],
          },
        ],
      },
      {
        id: "paragraph-after",
        type: "paragraph",
        content: "aaa",
      },
      {
        id: "trailing-paragraph",
        type: "paragraph",
      },
    ]);

    // Set cursor to the end of "paragraph-after"
    editor.setTextCursorPosition("paragraph-after", "end");

    // Press backspace 3 times to delete "aaa"
    for (let i = 0; i < 3; i++) {
      expect(() => pressBackspace(editor)).not.toThrow();
    }

    // Now cursor is at start of empty block. Press backspace to trigger
    // the columnList handler.
    expect(() => pressBackspace(editor)).not.toThrow();

    // Press backspace again - this should also not throw
    expect(() => pressBackspace(editor)).not.toThrow();
  });

  it("should handle rapid backspace presses after columnList without throwing", () => {
    const editor = createEditor();

    editor.replaceBlocks(editor.document, [
      {
        id: "column-list-0",
        type: "columnList",
        children: [
          {
            id: "column-0",
            type: "column",
            children: [
              {
                id: "col-0-p-0",
                type: "paragraph",
                content: "Column 0 Text",
              },
            ],
          },
          {
            id: "column-1",
            type: "column",
            children: [
              {
                id: "col-1-p-0",
                type: "paragraph",
                content: "Column 1 Text",
              },
            ],
          },
        ],
      },
      {
        id: "paragraph-after",
        type: "paragraph",
        content: "aaa",
      },
      {
        id: "trailing-paragraph",
        type: "paragraph",
      },
    ]);

    // Set cursor to the end of "paragraph-after"
    editor.setTextCursorPosition("paragraph-after", "end");

    // Rapidly press backspace multiple times
    for (let i = 0; i < 10; i++) {
      expect(() => pressBackspace(editor)).not.toThrow();
    }
  });

  it("should handle backspace when columnList is directly before block with no trailing paragraph", () => {
    const editor = createEditor();

    editor.replaceBlocks(editor.document, [
      {
        id: "column-list-0",
        type: "columnList",
        children: [
          {
            id: "column-0",
            type: "column",
            children: [
              {
                id: "col-0-p-0",
                type: "paragraph",
                content: "Column 0 Text",
              },
            ],
          },
          {
            id: "column-1",
            type: "column",
            children: [
              {
                id: "col-1-p-0",
                type: "paragraph",
                content: "Column 1 Text",
              },
            ],
          },
        ],
      },
      {
        id: "paragraph-after",
        type: "paragraph",
        content: "aaa",
      },
    ]);

    // Set cursor to the end of "paragraph-after"
    editor.setTextCursorPosition("paragraph-after", "end");

    // Rapidly press backspace multiple times
    for (let i = 0; i < 10; i++) {
      expect(() => pressBackspace(editor)).not.toThrow();
    }
  });
});

