import { describe, expect, it } from "vitest";
import { BlockNoteEditor, BlockNoteSchema } from "@blocknote/core";
import { ColumnBlock, ColumnListBlock } from "../../blocks/Columns/index.js";
import { keymap } from "prosemirror-keymap";
import { EditorState } from "prosemirror-state";

const testEditorSchema = BlockNoteSchema.create().extend({
  blockSpecs: {
    column: ColumnBlock,
    columnList: ColumnListBlock,
  } as const,
});

function createEditor() {
  const editor = BlockNoteEditor.create({
    schema: testEditorSchema,
  });
  const div = document.createElement("div");
  editor.mount(div);
  return editor;
}

/**
 * Simulates a Backspace key press by directly triggering ProseMirror's keymap.
 * We get the Backspace binding from the editor's keymap plugins and call it directly.
 */
function pressBackspace(editor: BlockNoteEditor): boolean {
  const view = editor._tiptapEditor.view;
  const state = view.state;

  // Try to find and invoke the Backspace keybinding
  // ProseMirror's keymap plugin stores bindings in its spec
  let result = false;
  for (const plugin of state.plugins) {
    const spec: any = plugin.spec;
    if (spec.key && spec.key.indexOf("keymap") !== -1) {
      // This is a keymap plugin - check if it handles Backspace
      const handleKeyDown = spec.props?.handleKeyDown;
      if (handleKeyDown) {
        const event = new KeyboardEvent("keydown", {
          key: "Backspace",
          code: "Backspace",
          keyCode: 8,
          which: 8,
          bubbles: true,
        });
        const handled = handleKeyDown(view, event);
        if (handled) {
          result = true;
        }
      }
    }
  }
  return result;
}

