/**
 * Simulates a Backspace key press by looking up and calling the Backspace
 * handler from the editor's keymap plugins directly.
 */
function pressBackspace(editor: BlockNoteEditor): boolean {
  const view = editor._tiptapEditor.view;
  const state = view.state;

  // Find all keymap plugins and look for Backspace bindings
  for (const plugin of state.plugins) {
    const spec: any = plugin.spec;
    // keymap plugins store their bindings in the spec
    if (spec.keyBindings) {
      const binding = spec.keyBindings["Backspace"];
      if (binding) {
        const result = binding(state, (tr: any) => view.dispatch(tr), view);
        if (result) {
          return true;
        }
      }
    }
  }

  // Fallback: use keyboardShortcut command
  return editor._tiptapEditor.commands.keyboardShortcut("Backspace");
}

