  const view = editor._tiptapEditor.view;
  const state = view.state;

  // Try to find and invoke the Backspace keybinding
  // ProseMirror's keymap plugin stores bindings in its spec
  let result = false;
  const event = new KeyboardEvent("keydown", {
    key: "Backspace",
    code: "Backspace",
    keyCode: 8,
    which: 8,
    bubbles: true,
